// Milanuncios tiene rate-limit anti-bot (PerimeterX): pocas marcas/noche, rotación lenta.
// 4 marcas/noche por día del año → ciclo completo ~17 noches.
const brands = ["peugeot","mercedes-benz","kia","citroen","volkswagen","ford","opel","renault","audi","seat","bmw","toyota","nissan","hyundai","fiat","mg","skoda","jeep","volvo","mazda","ds","cupra","dacia","mini","mitsubishi","lexus","land-rover","honda","suzuki","alfa-romeo","ssangyong","byd","porsche","jaguar","subaru","smart","dfsk","tesla","iveco","abarth","leapmotor","chevrolet","maserati","lancia","maxus","infiniti","ferrari","bentley","geely","chrysler","polestar","dodge","alpine","aston-martin","saab","dongfeng","ineos","mahindra","rover","cadillac","isuzu","lamborghini","lotus","hummer","maybach","omoda","jaecoo","tata","daewoo"];
const PER = 4;
const now = new Date();
const doy = Math.floor((Date.now() - Date.UTC(now.getUTCFullYear(), 0, 0)) / 86400000);
const groups = Math.ceil(brands.length / PER);
const g = doy % groups;
const mine = brands.slice(g * PER, g * PER + PER);
const out = [];
for (const b of mine) out.push({ json: { url: 'https://www.milanuncios.com/' + b + '-de-segunda-mano/' } });
return out;

// De la página 1 de cada marca: leer pagination.totalPages → generar ?pagina=N (tope CAP).
const inputs = $input.all();
const CAP = 10;
const out = [];
let sawBlock = false;
for (const inp of inputs) {
  const html = typeof inp.json === 'string' ? inp.json : String(inp.json.data || inp.json.body || '');
  if (/Pardon Our Interruption/i.test(html)) { sawBlock = true; continue; }
  let i = html.indexOf('window.__INITIAL_PROPS__');
  if (i < 0) continue;
  i = html.indexOf('"', i);
  let j = i + 1, esc = false, str = '';
  for (; j < html.length; j++) {
    const c = html[j];
    if (esc) { str += c; esc = false; }
    else if (c === '\\') { str += c; esc = true; }
    else if (c === '"') break;
    else str += c;
  }
  let pp;
  try { pp = JSON.parse(JSON.parse('"' + str + '"')); } catch (e) { continue; }
  const pag = pp.adListPagination;
  if (!pag || !pag.pagination) continue;
  const ads = (pag.adList && pag.adList.ads) || [];
  const catSlug = ads[0] && ads[0].category && ads[0].category.slug;
  if (!catSlug) continue;
  const baseUrl = 'https://www.milanuncios.com/' + catSlug + '/';
  const total = pag.pagination.totalPages || 1;
  const pages = Math.min(total, CAP);
  for (let p = 1; p <= pages; p++) out.push({ json: { url: baseUrl + '?pagina=' + p } });
}
if (out.length === 0) throw new Error('Milanuncios: 0 páginas generadas' + (sawBlock ? ' (bloqueo PerimeterX detectado en página 1)' : ''));
return out;

// Milanuncios – transform: HTML → window.__INITIAL_PROPS__ (string JSON) →
// adListPagination.adList.ads → UPSERT moveadvisor_market_offers (portal='milanuncios')
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');

// Rate-limit anti-bot (PerimeterX): si llega la página de bloqueo, PARAR el run
// (seguir pidiendo alarga el bloqueo). Lanzar error detiene el workflow entero.
if (/Pardon Our Interruption/i.test(html)) {
  throw new Error('Milanuncios bloqueado (PerimeterX) — run detenido para no alargar el bloqueo');
}

// --- extraer window.__INITIAL_PROPS__ (es un string JSON escapado: = JSON.parse("{...}")) ---
let ads = [];
try {
  let i = html.indexOf('window.__INITIAL_PROPS__');
  if (i >= 0) {
    i = html.indexOf('"', i);
    let j = i + 1, esc = false, out = '';
    for (; j < html.length; j++) {
      const c = html[j];
      if (esc) { out += c; esc = false; }
      else if (c === '\\') { out += c; esc = true; }
      else if (c === '"') break;
      else out += c;
    }
    const pp = JSON.parse(JSON.parse('"' + out + '"'));
    ads = (pp.adListPagination && pp.adListPagination.adList && pp.adListPagination.adList.ads) || [];
  }
} catch (e) { ads = []; }
if (!ads.length) return [{ json: { sql: null, count: 0 } }];

function esc(v) {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'number') return isNaN(v) ? 'NULL' : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}
function cleanBrand(s) {
  s = String(s || '').replace(/-/g, ' ').replace(/\s+/g, ' ').trim();
  return s.replace(/\b\w/g, c => c.toUpperCase());
}
function normFuel(s) {
  s = String(s || '').toLowerCase();
  const ench = (s.indexOf('enchufable') !== -1 || s.indexOf('plug') !== -1) && s.indexOf('no enchufable') === -1;
  if (s.indexOf('diesel') !== -1 || s.indexOf('diésel') !== -1 || s.indexOf('gasoil') !== -1 || s.indexOf('gasóleo') !== -1) return 'Diesel';
  if (s.indexOf('híbrido') !== -1 || s.indexOf('hibrido') !== -1 || s.indexOf('hybrid') !== -1) return ench ? 'Híbrido enchufable' : 'Híbrido';
  if (s.indexOf('eléctric') !== -1 || s.indexOf('electric') !== -1) return 'Eléctrico';
  if (s.indexOf('gasolina') !== -1) return 'Gasolina';
  if (s.indexOf('glp') !== -1 || s.indexOf('gnc') !== -1 || s.indexOf('gas') !== -1) return 'Gas';
  return '';
}
function normGear(s) { s = String(s || '').toLowerCase(); if (s.indexOf('autom') !== -1) return 'Automatica'; if (s.indexOf('manual') !== -1) return 'Manual'; return ''; }
function digits(s) { const m = String(s || '').replace(/\./g, '').match(/\d+/); return m ? parseInt(m[0], 10) : null; }
function tag(a, type) { const t = (a.tags || []).find(x => x && x.type === type); return t ? t.text : ''; }

const rows = [];
for (const a of ads) {
  if (!a || !a.id) continue;
  const price = a.price && a.price.cashPrice && a.price.cashPrice.value != null ? a.price.cashPrice.value : null;
  if (price === null) continue; // precio obligatorio

  const id = 'mil_' + a.id;
  const brand = cleanBrand(a.category && a.category.name);
  const title = String(a.title || '').replace(/\s+/g, ' ').trim();
  // modelo/versión: quitar la marca del principio del título
  let rest = title;
  const bl = (a.category && a.category.name ? a.category.name.replace(/-/g, ' ') : '').toLowerCase();
  if (bl && title.toLowerCase().indexOf(bl) === 0) rest = title.slice(bl.length).trim();
  else { const bw = (brand.split(' ')[0] || '').toLowerCase(); if (bw && title.toLowerCase().indexOf(bw) === 0) rest = title.slice(bw.length).trim(); }
  const sp = rest.indexOf(' ');
  const model = sp === -1 ? rest : rest.slice(0, sp);
  const version = sp === -1 ? '' : rest.slice(sp + 1).trim();

  const year = digits(tag(a, 'año'));
  const mileage = digits(tag(a, 'kilómetros'));
  const fuel = normFuel(tag(a, 'combustible'));
  const transmission = normGear(tag(a, 'cambio'));

  const prov = (a.province && a.province.name) || (a.location && a.location.province && a.location.province.name) || '';
  const city = (a.location && a.location.city && a.location.city.name) || (a.city && a.city.name) || '';
  const sellerType = a.sellerType === 'private' ? 'particular' : 'profesional';
  const dealerName = sellerType === 'profesional' ? String(a.seoTitle || '') : '';

  const imgs = (Array.isArray(a.images) ? a.images : [])
    .map(u => u ? ('https://' + String(u).replace(/^https?:\/\//, '')) : null).filter(Boolean).slice(0, 15);
  const imageUrl = imgs[0] || '';
  const imagesJson = JSON.stringify(imgs).replace(/'/g, "''");
  const url = a.url ? ('https://www.milanuncios.com' + a.url) : '';

  const row = '(' +
    esc(id) + ", 'milanuncios', " + esc(url) + ', ' + esc(title) + ', ' + esc(brand) + ', ' + esc(model) + ', ' + esc(version) + ', ' +
    (year || 'NULL') + ', ' + (mileage != null ? mileage : 'NULL') + ', ' + price + ', ' +
    esc(fuel) + ', ' + esc(transmission) + ", '', " +
    esc(imageUrl) + ", '" + imagesJson + "', '', " + esc(dealerName) + ', ' +
    esc(city) + ', ' + esc(prov) + ', ' + esc(prov) + ', ' +
    "'" + sellerType + "', 'compra', " +
    'NULL, NULL, ' + "'', NULL, NULL" +
    ', NOW(), NOW(), NOW()' +
  ')';
  rows.push(row);
}
if (!rows.length) return [{ json: { sql: null, count: 0 } }];

const cols = 'id, portal, url, title, brand, model, version, year, mileage, price, fuel, transmission, color, ' +
  'image_url, images, environmental_label, dealer_name, city, province, location, seller_type, listing_type, ' +
  'power_cv, power_kw, body_type, doors, seats, first_seen_at, scraped_at, last_seen_at';

const onConflict = 'ON CONFLICT (id) DO UPDATE SET ' +
  'url = EXCLUDED.url, title = EXCLUDED.title, price = EXCLUDED.price, mileage = EXCLUDED.mileage, ' +
  'year = COALESCE(EXCLUDED.year, moveadvisor_market_offers.year), ' +
  'fuel = EXCLUDED.fuel, transmission = EXCLUDED.transmission, seller_type = EXCLUDED.seller_type, ' +
  "image_url = COALESCE(NULLIF(moveadvisor_market_offers.image_url,''), EXCLUDED.image_url), " +
  "images = COALESCE(NULLIF(moveadvisor_market_offers.images,''), EXCLUDED.images), " +
  'last_seen_at = NOW(), updated_at = NOW()';

const sql = 'INSERT INTO moveadvisor_market_offers (' + cols + ') VALUES ' + rows.join(', ') + ' ' + onConflict;
return [{ json: { sql: sql, count: rows.length } }];
